function parseMessage(input) {
  if (typeof input?.message === 'string') {
    try {
      return JSON.parse(input.message);
    } catch (error) {
      return input;
    }
  }

  if (input?.message && typeof input.message === 'object') {
    return input.message;
  }

  return input;
}

function toIso(value) {
  if (!value) return new Date().toISOString();
  if (typeof value === 'number') {
    const millis = value > 1e12 ? value : value * 1000;
    return new Date(millis).toISOString();
  }

  const parsed = Date.parse(value);
  return Number.isNaN(parsed) ? new Date().toISOString() : new Date(parsed).toISOString();
}

function dayKey(isoString) {
  const date = new Date(isoString);
  const year = date.getFullYear();
  const month = String(date.getMonth() + 1).padStart(2, '0');
  const day = String(date.getDate()).padStart(2, '0');
  return year + '-' + month + '-' + day;
}

const raw = parseMessage($json);
const eventTs = toIso(raw.timestamp ?? raw.event_ts);

return {
  event_ts: eventTs,
  day: dayKey(eventTs),
  printer_id: raw.printer_id ?? 'p1s_01',
  event_type: raw.inferred_event_type ?? raw.event_type ?? 'status_changed',
  transition_from: raw.old_state ?? '',
  transition_to: raw.new_state ?? '',
  progress_pct: Number(raw?.snapshot?.progress ?? 0),
  duration_sec: Number(raw.duration_sec ?? raw?.snapshot?.duration_sec ?? raw?.snapshot?.elapsed_time_s ?? 0),
  job_id: raw.job_id ?? raw?.snapshot?.job_id ?? raw?.snapshot?.task_name ?? raw.task_name ?? raw.event_id ?? '',
  raw_payload: JSON.stringify(raw)
};

function dayKey(date = new Date()) {
  const year = date.getFullYear();
  const month = String(date.getMonth() + 1).padStart(2, '0');
  const day = String(date.getDate()).padStart(2, '0');
  return `${year}-${month}-${day}`;
}

return [{
  json: {
    day: dayKey()
  }
}];

function toMillis(value) {
  if (!value) return Date.now();
  if (typeof value === 'number') return value > 1e12 ? value : value * 1000;
  const parsed = Date.parse(value);
  return Number.isNaN(parsed) ? Date.now() : parsed;
}

const rows = $input.all()
  .map((item) => item.json)
  .sort((left, right) => toMillis(left.event_ts) - toMillis(right.event_ts));

if (rows.length === 0) {
  return [];
}

const aggregates = new Map();
const activeStarts = new Map();
const snapshotTs = new Date().toISOString();

for (const row of rows) {
  const printerId = row.printer_id ?? 'unknown';

  if (!aggregates.has(printerId)) {
    aggregates.set(printerId, {
      snapshot_ts: snapshotTs,
      day: row.day,
      printer_id: printerId,
      events: 0,
      started: 0,
      completed: 0,
      failed: 0,
      total_duration_sec: 0,
      active_jobs: 0
    });
  }

  const stats = aggregates.get(printerId);
  const eventTs = toMillis(row.event_ts);
  stats.events += 1;

  if (row.event_type === 'print_started') {
    stats.started += 1;
    activeStarts.set(printerId, eventTs);
    continue;
  }

  if (row.event_type === 'print_completed') {
    stats.completed += 1;
    if (activeStarts.has(printerId)) {
      const startedAt = activeStarts.get(printerId);
      stats.total_duration_sec += Math.max(0, Math.round((eventTs - startedAt) / 1000));
      activeStarts.delete(printerId);
    }
    continue;
  }

  if (row.event_type === 'print_failed') {
    stats.failed += 1;
    activeStarts.delete(printerId);
  }
}

return Array.from(aggregates.values()).map((stats) => {
  const completionBase = stats.completed + stats.failed;
  const failureRate = completionBase > 0 ? Number((stats.failed / completionBase).toFixed(4)) : 0;
  const avgDurationSec = stats.completed > 0 ? Math.round(stats.total_duration_sec / stats.completed) : 0;

  return {
    json: {
      ...stats,
      failure_rate: failureRate,
      avg_duration_sec: avgDurationSec,
      active_jobs: activeStarts.has(stats.printer_id) ? 1 : 0
    }
  };
});
